SELECT MAX(employment_rate) AS 'Maximum Employment Rate'
FROM employment_data
WHERE category_id IN (
    SELECT category_id
    FROM job_categories
    WHERE median_salary > (
        SELECT AVG(median_salary)
        FROM job_categories
    )
) AND year > 2017;

SELECT AVG(median_salary) AS average_pay_rate
FROM job_categories
WHERE category_name = 'Community Service, Legal, Arts, and Media';

SELECT MAX(average_salary) AS highest_average_salary
FROM employment_data
WHERE category_id IN (SELECT category_id FROM job_categories WHERE industry_sector_id = 1);
